+        test_home.path(),
+        &["models", "status", "--json"],
+        ExpectStatus::ExitOk,
+    );
+    let canonical =
+        serde_json::to_string_pretty(&json_value_schema(&status)).expect("pretty-print JSON");
+    assert_golden("robot/models_status_shape.json.golden", &canonical);
+}
